using System;\nusing System.Net;\nusing System.Net.WebSockets;\nusing System.Threading;\nusing System.Threading.Tasks;\nusing Xunit;\nusing Moq;\nusing Microsoft.Extensions.Logging;\nusing PitWall.WebSocket;\nusing PitWall.Models;\n\nnamespace PitWall.Tests.Unit.WebSocket\n{\n    /// <summary>\n    /// Unit tests for WebSocketServer component.\n    /// Tests server initialization, client connection management, and telemetry broadcast.\n    /// </summary>\n    public class WebSocketServerTests : IAsyncLifetime\n    {\n        private WebSocketServer _server;\n        private Mock<ILogger<WebSocketServer>> _mockLogger;\n        private CancellationTokenSource _testCancellation;\n        private const int TestPort = 9998; // Use non-standard port for testing\n\n        public async Task InitializeAsync()\n        {\n            _mockLogger = new Mock<ILogger<WebSocketServer>>();\n            _testCancellation = new CancellationTokenSource();\n            _server = new WebSocketServer(_mockLogger.Object, TestPort);\n            await _server.StartAsync(_testCancellation.Token);\n        }\n\n        public async Task DisposeAsync()\n        {\n            _testCancellation.Cancel();\n            await _server.StopAsync(CancellationToken.None);\n            _server?.Dispose();\n            _testCancellation?.Dispose();\n        }\n\n        [Fact]\n        public void Constructor_WithValidLogger_InitializesServer()\n        {\n            // Arrange\n            var logger = new Mock<ILogger<WebSocketServer>>();\n\n            // Act\n            var server = new WebSocketServer(logger.Object, 9999);\n\n            // Assert\n            Assert.NotNull(server);\n            Assert.False(server.IsRunning);\n        }\n\n        [Fact]\n        public void Constructor_WithNullLogger_ThrowsArgumentNullException()\n        {\n            // Act & Assert\n            Assert.Throws<ArgumentNullException>(() => new WebSocketServer(null!, 9999));\n        }\n\n        [Fact]\n        public async Task StartAsync_WithValidCancellation_StartsServer()\n        {\n            // Arrange\n            var logger = new Mock<ILogger<WebSocketServer>>();\n            var server = new WebSocketServer(logger.Object, 9997);\n            var cts = new CancellationTokenSource();\n\n            try\n            {\n                // Act\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100); // Allow server to initialize\n\n                // Assert\n                Assert.True(server.IsRunning);\n            }\n            finally\n            {\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n                server.Dispose();\n            }\n        }\n\n        [Fact]\n        public async Task StopAsync_WhenRunning_StopsServer()\n        {\n            // Arrange\n            var logger = new Mock<ILogger<WebSocketServer>>();\n            var server = new WebSocketServer(logger.Object, 9996);\n            var cts = new CancellationTokenSource();\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n                Assert.True(server.IsRunning);\n\n                // Act\n                await server.StopAsync(CancellationToken.None);\n                await Task.Delay(100);\n\n                // Assert\n                Assert.False(server.IsRunning);\n            }\n            finally\n            {\n                cts.Cancel();\n                server.Dispose();\n            }\n        }\n\n        [Fact]\n        public void ConnectedClientsCount_Initially_ReturnsZero()\n        {\n            // Act\n            var count = _server.ConnectedClientsCount;\n\n            // Assert\n            Assert.Equal(0, count);\n        }\n\n        [Fact]\n        public void Port_AfterConstruction_MatchesProvidedValue()\n        {\n            // Arrange\n            var logger = new Mock<ILogger<WebSocketServer>>();\n\n            // Act\n            var server = new WebSocketServer(logger.Object, 8888);\n\n            // Assert\n            Assert.Equal(8888, server.Port);\n        }\n\n        [Fact]\n        public void GetServerStatistics_WhenInitialized_ReturnsValidStatistics()\n        {\n            // Act\n            var stats = _server.GetServerStatistics();\n\n            // Assert\n            Assert.NotNull(stats);\n            Assert.Equal(0, stats.ConnectedClients);\n            Assert.True(stats.UpcomingConnectionAttempts >= 0);\n            Assert.True(stats.TotalConnections >= 0);\n        }\n\n        [Fact]\n        public void Port_WithInvalidPort_StillInitializes()\n        {\n            // Arrange\n            var logger = new Mock<ILogger<WebSocketServer>>();\n\n            // Act\n            var server = new WebSocketServer(logger.Object, 0); // Port 0 is technically invalid but accepted\n\n            // Assert\n            Assert.NotNull(server);\n            Assert.Equal(0, server.Port);\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_WithValidSnapshot_SendsToAllClients()\n        {\n            // Arrange\n            var snapshot = CreateTestTelemetrySnapshot();\n\n            // Act\n            await _server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n\n            // Assert - Server should accept broadcast without error\n            Assert.NotNull(_server);\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_WithNullSnapshot_DoesNotThrow()\n        {\n            // Act & Assert - Should not throw\n            await _server.BroadcastTelemetryAsync(null!, CancellationToken.None);\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_WithCancellation_CompletesOrCancels()\n        {\n            // Arrange\n            var snapshot = CreateTestTelemetrySnapshot();\n            var cts = new CancellationTokenSource();\n            cts.CancelAfter(TimeSpan.FromSeconds(1));\n\n            // Act\n            try\n            {\n                await _server.BroadcastTelemetryAsync(snapshot, cts.Token);\n            }\n            catch (OperationCanceledException)\n            {\n                // Expected behavior\n            }\n\n            // Assert\n            Assert.True(cts.Token.IsCancellationRequested);\n        }\n\n        [Fact]\n        public void GetConnectionStatistics_WithNoClients_ReturnsEmptyList()\n        {\n            // Act\n            var stats = _server.GetConnectionStatistics();\n\n            // Assert\n            Assert.NotNull(stats);\n            Assert.Empty(stats);\n        }\n\n        private static TelemetrySnapshot CreateTestTelemetrySnapshot()\n        {\n            return new TelemetrySnapshot\n            {\n                Timestamp = DateTime.UtcNow,\n                SessionId = \"test-session-123\",\n                VehicleData = new VehicleData\n                {\n                    Speed = 150.5f,\n                    Throttle = 0.85f,\n                    Brake = 0.0f,\n                    Clutch = 0.0f,\n                    Gear = 4,\n                    EngineRpm = 7500,\n                    FuelRemaining = 45.5f,\n                    MaxFuel = 80.0f,\n                    SteeringAngle = 0.15f,\n                    InvalidFlagBits = 0\n                },\n                TireData = new TireInfo[4]\n                {\n                    new TireInfo { Temperature = 95.5f, Pressure_Kpa = 220.0f, Wear = 0.15f, Load = 0.8f },\n                    new TireInfo { Temperature = 94.2f, Pressure_Kpa = 218.0f, Wear = 0.14f, Load = 0.8f },\n                    new TireInfo { Temperature = 92.8f, Pressure_Kpa = 215.0f, Wear = 0.16f, Load = 0.7f },\n                    new TireInfo { Temperature = 93.5f, Pressure_Kpa = 217.0f, Wear = 0.15f, Load = 0.7f }\n                },\n                PerformanceData = new PerformanceData\n                {\n                    LateralAccelerationG = 1.2f,\n                    LongitudinalAccelerationG = 0.8f,\n                    VerticalAccelerationG = 0.1f,\n                    LapNumber = 5,\n                    LapTime_Seconds = 95.234f,\n                    BestLapTime_Seconds = 92.156f\n                },\n                EnvironmentData = new EnvironmentData\n                {\n                    AirTemperature = 22.5f,\n                    RoadTemperature = 25.0f,\n                    RacingLine = 0.5f,\n                    RollAngle = 0.05f,\n                    PitchAngle = -0.02f,\n                    YawAngle = 0.15f\n                }\n            };\n        }\n    }\n}\n